import { Link, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { clearAuth, getAuth } from "../utils/auth";

export default function Navbar() {
  const navigate = useNavigate();
  const [auth, setAuthState] = useState(getAuth());

  useEffect(() => {
    const refresh = () => setAuthState(getAuth());
    window.addEventListener("auth-change", refresh);
    window.addEventListener("storage", refresh);
    return () => {
      window.removeEventListener("auth-change", refresh);
      window.removeEventListener("storage", refresh);
    };
  }, []);

  const logout = () => {
    clearAuth();
    navigate("/login");
  };

  const isLogged = !!auth?.token;
  const role = auth?.role;

  const isCustomer = isLogged && role === "user";
  const isStaff = isLogged && (role === "staff" || role === "manager" || role === "admin");
  const isManager = isLogged && (role === "manager" || role === "admin");
  const isAdmin = isLogged && role === "admin";

  return (
    <div style={{ position: "sticky", top: 0, zIndex: 20, backdropFilter: "blur(10px)" }}>
      <nav
        className="card"
        style={{
          borderRadius: 0,
          borderLeft: "none",
          borderRight: "none",
          padding: "12px 0",
          background: "rgba(11,15,13,0.72)",
        }}
      >
        <div className="container row">
          <Link to="/" style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <div
              style={{
                width: 34,
                height: 34,
                borderRadius: 12,
                border: "1px solid rgba(34,197,94,0.35)",
                background: "rgba(34,197,94,0.10)",
                display: "grid",
                placeItems: "center",
                fontWeight: 900,
              }}
            >
              A
            </div>
            <div>
              <div style={{ fontWeight: 900, letterSpacing: 0.2 }}>AutoPulse</div>
              <div className="sub">Car Dealership System</div>
            </div>
          </Link>

          <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
            <Link className="btn" to="/vehicles">Vehicles</Link>

            {!isLogged && (
              <>
                <Link className="btn btnPrimary" to="/login">Login</Link>
                <Link className="btn" to="/register">Register</Link>
              </>
            )}

            {isCustomer && (
              <>
                <Link className="btn" to="/book-appointment">Book</Link>
                <Link className="btn" to="/my-appointments">My Appointments</Link>
                <button className="btn" onClick={logout}>Logout</button>
              </>
            )}

            {isStaff && (
              <>
                <Link className="btn" to="/appointments">Appointments</Link>
                <Link className="btn" to="/documents">Documents</Link>

                {isManager && (
                  <>
                    <Link className="btn" to="/vehicles/add">Add Vehicle</Link>
                    <Link className="btn" to="/sales">Sales</Link>
                  </>
                )}

                {isAdmin && (
                  <Link className="btn" to="/admin/create-staff">Create Staff</Link>
                )}

                <button className="btn" onClick={logout}>Logout</button>
              </>
            )}
          </div>
        </div>
      </nav>
    </div>
  );
}
